sys_ws_operation.operation_script:
(function process(request, response) {
                var caseNumber = request.pathParams.case_number;
                var gr = new GlideRecord('x_2091449_manage_0_consumer_case');
                gr.addQuery('number', caseNumber);
                gr.setLimit(1);
                gr.query();

                if (gr.next()) {
                    var caseSysId = gr.getUniqueValue();

                    // Get interactions
                    var interactions = [];
                    var intGr = new GlideRecord('x_2091449_manage_0_channel_interaction');
                    intGr.addQuery('consumer_case', caseSysId);
                    intGr.orderBy('sys_created_on');
                    intGr.query();
                    while (intGr.next()) {
                        interactions.push({
                            sys_id: intGr.getUniqueValue(),
                            channel: intGr.getValue('channel'),
                            interaction_type: intGr.getValue('interaction_type'),
                            message_body: intGr.getValue('message_body'),
                            sentiment: intGr.getValue('sentiment'),
                            created_on: intGr.getValue('sys_created_on')
                        });
                    }

                    response.setStatus(200);
                    response.setBody({
                        case_number: caseNumber,
                        case_sys_id: caseSysId,
                        short_description: gr.getValue('short_description'),
                        channel: gr.getValue('channel'),
                        channel_detail: gr.getValue('channel_detail'),
                        state: gr.getValue('state'),
                        priority: gr.getValue('priority'),
                        interaction_count: gr.getValue('interaction_count'),
                        customer_name: gr.getValue('customer_name'),
                        customer_email: gr.getValue('customer_email'),
                        interactions: interactions
                    });
                } else {
                    response.setStatus(404);
                    response.setBody({ success: false, error: 'Case not found: ' + caseNumber });
                }
            })(request, response)
